import React, { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useFormik } from 'formik';
import { toast } from 'react-toastify';
import Layout from '../../components/shared/Layout';
import axiosInstance from '../../utils/axiosInstance';
import { fetchMyLoans } from '../../store/slices/loanSlice';
import { fetchMyAccounts } from '../../store/slices/accountSlice';
import { loanSchema } from '../../schemas';

const StatusBadge = ({ status }) => {
  const colors = { PENDING: ['#f59e0b', '#fef3c7'], APPROVED: ['#22c55e', '#dcfce7'], REJECTED: ['#ef4444', '#fee2e2'] };
  const [color, bg] = colors[status] || ['#94a3b8', '#f1f5f9'];
  return <span style={{ padding: '3px 12px', borderRadius: 99, background: bg, color, fontWeight: 700, fontSize: 12 }}>{status}</span>;
};

export default function LoanPage() {
  const dispatch = useDispatch();
  const { loans, loading } = useSelector(s => s.loans);
  const { accounts } = useSelector(s => s.accounts);
  const [showForm, setShowForm] = useState(false);
  const [emiInfo, setEmiInfo] = useState(null);

  useEffect(() => { dispatch(fetchMyLoans()); dispatch(fetchMyAccounts()); }, [dispatch]);

  const activeAccount = accounts.find(a => a.status === 'ACTIVE');

  const formik = useFormik({
    initialValues: { loanAmount: '', interestRate: '10', tenureMonths: '12', purpose: '' },
    validationSchema: loanSchema,
    onSubmit: async (values, { resetForm }) => {
      try {
        await axiosInstance.post('/loans/apply', { ...values, accountNumber: activeAccount?.accountNumber });
        toast.success('Loan application submitted!');
        dispatch(fetchMyLoans());
        resetForm(); setShowForm(false); setEmiInfo(null);
      } catch (err) { toast.error(err.response?.data?.message || 'Application failed'); }
    }
  });

  const calcEmi = async () => {
    const { loanAmount, interestRate, tenureMonths } = formik.values;
    if (!loanAmount || !interestRate || !tenureMonths) return;
    try {
      const { data } = await axiosInstance.post('/loans/calculate-emi', { principal: loanAmount, rate: interestRate, months: tenureMonths });
      setEmiInfo(data);
    } catch {}
  };

  const payEmi = async (loanId) => {
    try {
      await axiosInstance.post(`/loans/${loanId}/pay-emi`);
      toast.success('EMI paid!');
      dispatch(fetchMyLoans()); dispatch(fetchMyAccounts());
    } catch (err) { toast.error(err.response?.data?.message || 'Payment failed'); }
  };

  const inp = { padding: '10px 14px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 14, width: '100%', boxSizing: 'border-box', marginBottom: 12 };

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <div className="d-flex flex-wrap justify-content-between align-items-center gap-3 mb-4">
          <h2 className="mb-0" style={{ color: '#1e293b' }}>🏦 Loans</h2>
          {activeAccount && (
            <button
              onClick={() => setShowForm(!showForm)}
              className="btn"
              style={{ padding: '10px 20px', borderRadius: 8, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 700 }}
            >
              + Apply for Loan
            </button>
          )}
        </div>
      </div>

      {showForm && (
        <div className="row mb-4">
          <div className="col-12 col-md-8 col-lg-6">
            <div style={{ background: '#fff', borderRadius: 12, padding: 28, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
              <h3 className="mb-4">Apply for Loan</h3>
              <form onSubmit={formik.handleSubmit}>
                {[['loanAmount', '₹ Loan Amount'], ['interestRate', 'Interest Rate (%)'], ['tenureMonths', 'Tenure (Months)'], ['purpose', 'Purpose']].map(([name, lbl]) => (
                  <div key={name}>
                    <label style={{ fontSize: 13, fontWeight: 600 }}>{lbl}</label>
                    <input type={name === 'purpose' ? 'text' : 'number'} style={inp} placeholder={lbl} {...formik.getFieldProps(name)} onBlur={calcEmi} />
                    {formik.touched[name] && formik.errors[name] && <div style={{ color: '#ef4444', fontSize: 12, marginTop: -8, marginBottom: 8 }}>{formik.errors[name]}</div>}
                  </div>
                ))}
                {emiInfo && (
                  <div style={{ background: '#f0fdf4', borderRadius: 8, padding: 14, marginBottom: 16, border: '1px solid #bbf7d0' }}>
                    <strong>EMI: ₹{emiInfo.emi?.toLocaleString('en-IN')}/month</strong>
                    <p style={{ margin: '4px 0 0', fontSize: 13, color: '#64748b' }}>Total: ₹{emiInfo.totalPayable?.toLocaleString('en-IN')} · Interest: ₹{emiInfo.totalInterest?.toLocaleString('en-IN')}</p>
                  </div>
                )}
                <button type="submit" style={{ width: '100%', padding: 12, borderRadius: 8, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>Submit Application</button>
              </form>
            </div>
          </div>
        </div>
      )}

      {loading ? <p>Loading...</p> : (
        <div className="d-flex flex-column gap-3">
          {loans.length === 0 && <div style={{ background: '#fff', borderRadius: 12, padding: 32, textAlign: 'center', color: '#94a3b8' }}>No loan applications yet</div>}
          {loans.map(loan => (
            <div key={loan.loanId} style={{ background: '#fff', borderRadius: 12, padding: 24, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
              <div className="d-flex flex-wrap justify-content-between align-items-center gap-2 mb-3">
                <div>
                  <span style={{ fontFamily: 'monospace', color: '#64748b', fontSize: 13 }}>{loan.loanId}</span>
                  <h4 className="mb-0 mt-1" style={{ color: '#1e293b' }}>{loan.purpose}</h4>
                </div>
                <StatusBadge status={loan.status} />
              </div>
              {/* Loan details — wrap on mobile */}
              <div className="d-flex flex-wrap gap-4">
                <div><p style={{ margin: 0, fontSize: 12, color: '#94a3b8' }}>Amount</p><p style={{ margin: 0, fontWeight: 700 }}>₹{loan.loanAmount?.toLocaleString('en-IN')}</p></div>
                <div><p style={{ margin: 0, fontSize: 12, color: '#94a3b8' }}>EMI</p><p style={{ margin: 0, fontWeight: 700 }}>₹{loan.emi?.toLocaleString('en-IN')}/mo</p></div>
                <div><p style={{ margin: 0, fontSize: 12, color: '#94a3b8' }}>Tenure</p><p style={{ margin: 0, fontWeight: 700 }}>{loan.tenureMonths} months</p></div>
                <div><p style={{ margin: 0, fontSize: 12, color: '#94a3b8' }}>Rate</p><p style={{ margin: 0, fontWeight: 700 }}>{loan.interestRate}%</p></div>
              </div>
              {loan.status === 'APPROVED' && (
                <button onClick={() => payEmi(loan.loanId)} className="btn mt-3" style={{ padding: '8px 20px', borderRadius: 8, border: 'none', background: '#22c55e', color: '#fff', fontWeight: 700 }}>
                  Pay EMI ₹{loan.emi?.toLocaleString('en-IN')}
                </button>
              )}
              {loan.adminComment && <p style={{ margin: '12px 0 0', fontSize: 13, color: '#ef4444' }}>Note: {loan.adminComment}</p>}
            </div>
          ))}
        </div>
      )}
    </Layout>
  );
}
